var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저쪽도 문제가 심각한 모양이네.","JPN":"向こうの状況も相当厳しいんだね。","ENG":"Sounds like things are pretty bad over there too.","TWN":"那邊的問題好像也很嚴重呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그럴 만도 하죠.","JPN":"まあ、それもそのはずでしょう。","ENG":"Haha, I bet.","TWN":"哈哈，怎麼可能不嚴重。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"우리와는 관할 구역의 넓이가 차원이 다를 테니까요.","JPN":"僕たちとは、管轄区域の広さがまるで違うはずなので。","ENG":"Their jurisdiction is far more extensive than what we usually deal with.","TWN":"他們和我們管轄區域的範圍是不同次元的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 스승님. 대체 실비아 양까지 움직여 가면서 무슨 정보를 찾으신 겁니까?","JPN":"ところで師匠。シルビアさんに\\n頼ってまで、いったいどんな情報を探していたんですか。","ENG":"By the way, Master. What is it that you're looking for that you enlisted Sylvia’s assistance?","TWN":"話說回來，師父，到底是要找什麼資料，竟然要出動希爾維亞小姐？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 그건 제가 설명해 드릴게요.","JPN":"あ、それは私のほうから説明します。","ENG":"Oh, I can explain that.","TWN":"啊，這個我來解釋一下。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"몇 시간 전, 이상 침식 현상이 벌어진 직후에 외교 라인을 통해 쿠퍼 양으로부터 특정 초상현상에 관한 사건 기록을 검색해 달라는 연락을 받았습니다.","JPN":"数時間前、異常侵食現象が起きた直後に、外交筋を通じて\\nクーパーさんから特定の超常現象に関する事件記録を調査してほしいとの連絡を受けました。","ENG":"A few hours ago, right after the Counterside Effect began, we got word through diplomatic channels that Ms. Cooper requested a search of certain supernatural incidents.","TWN":"異常侵蝕現象發生之後，就在幾個小時前，庫博小姐透過外交部門希望我們幫忙搜索特定異常現象的事件。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저희 부서에도 협조 요청이 들어왔는데, 마침 저희가 수사 중이던 사건 중에 관련 있어 보이는 게 있어서 말이죠.","JPN":"うちの部署にも協力要請が入ってきたのですが、ちょうど私たちが捜査中だった事件と関連がありそうでして。","ENG":"They even reached out to our office, and it just so happened that we've been working on a similar case.","TWN":"因為我們正在搜查的事件中有相關資訊，所以我們部門也收到了協助請求。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 사건을 찾아 달라고 한 건데?","JPN":"どんな事件を調べて欲しいと言われたの？","ENG":"What incidents was she searching for exactly?","TWN":"你們要調查什麼事件？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>부활</color>입니다.","JPN":"<color=#ffd34c>復活</color>です。","ENG":"<color=#ffd34c>Resurrection</color>.","TWN":"是<color=#ffd34c>復活事件</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"정확히는 최근 2년 이내에, 카운터가 아닌 일반인에게서 발생한 대규모의 부활.","JPN":"厳密にはここ2年以内に、カウンターではなく一般人に起きた大規模な復活現象。","ENG":"Specifically, the mass resurrection of ordinary, non-Counter folks that occurred within the past two years.","TWN":"準確的說是最近2年內，在非制裁者的一般人中發生的大規模復活事件。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"혹은 그에 준하는 초재생 현상에 대한 사건 기록입니다.","JPN":"またはそれに準ずる超再生現象についての事件記録です。","ENG":"Or other records on similar supernatural regeneration short of outright resurrection.","TWN":"或者是超再生現象的相關記錄。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호오....... 그런 일이 있었나요?","JPN":"ほほう……そんなことがあったのですか？","ENG":"Ooh... So did you find anything?","TWN":"哦……還有這種事情嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"대략 1년쯤 전부터 암시장을 통해 급속히 퍼져나가기 시작한 약물이 있습니다.","JPN":"1年くらい前から闇市で急速に普及した薬があります。","ENG":"There’s this drug that’s been spreading rapidly through black market for about a year now.","TWN":"大概1年前，有一種藥物通過黑市，開始在世間快速流行。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이름은 <color=#ffd34c>엘릭서</color>.","JPN":"名前は、<color=#ffd34c>エリクサー</color>。","ENG":"It's called <color=#ffd34c>Elixir</color>.","TWN":"藥名是<color=#ffd34c>聖水</color>。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"정확한 조제법은 알 수 없지만......","JPN":"正確な調剤方法はわかりませんが……","ENG":"We’re not exactly sure how it's made...","TWN":"確切的調製方法雖然不太清楚……"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아마 이터니움을 베이스로 한 향정신성 약물, 통칭 카운터 드러그로 추정됩니다.","JPN":"エタニウムをベースとした向精神薬、通称カウンタードラッグとみられています。","ENG":"But we estimate that it's a type of a psychotropic substance with an Eternium base, also known as a “Counter drug.”","TWN":"但大概是一種以永恆之金為基礎的精神類藥物，通稱為制裁者毒品的東西。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"특이한 것은 다른 카운터 드러그와는 달리, 일반 중독자들뿐만 아니라 용병들 사이에서도 인기가 높았다는 점인데요.","JPN":"注目すべき点は、他のカウンタードラッグとは異なり、\\n一般中毒者だけでなく傭兵の間でも人気が高いということです。","ENG":"What’s interesting is that unlike other Counter drugs, Elixir has been popular among not only the usual addicts but also mercenaries.","TWN":"最特異的是，它和一般的制裁者毒品不同，不只是普通的成癮者，在傭兵之間也很受歡迎。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"투약시 일시적으로 카운터 능력자에 준하는 신체 능력을 부여하는 것은 물론......","JPN":"投薬すると、一時的にカウンター能力者に準ずる身体能力が得られるほか……","ENG":"Once administered, the drug not only grants physical capabilities that rival those of Counters...","TWN":"使用時，除了可以短暫的擁有制裁者的身體能力之外……"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"즉사할 정도의 상처를 입어도 기적적으로 상처가 재생되어 살아남을 수 있다고 합니다.","JPN":"即死するほどの大怪我をしても奇跡のように傷が修復し、生き延びることができるそうです。","ENG":"...but also allows the subjects to miraculously recover from fatal wounds.","TWN":"就算是受到致命傷，也可以奇蹟般地恢復，從鬼門關裡救回來。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"공식적으로 확인되지는 않았지만, 분명 사망이 확정된 사람이 엘릭서의 투여 후 소생했다는 증언도 있습니다.","JPN":"正式に認められたわけではありませんが、死亡した人がエリクサーの投与後に蘇ったという証言もあります。","ENG":"Although it hasn’t been officially vetted yet, there are testimonies of people administered with Elixir coming back to life after they've been pronounced dead.","TWN":"雖然沒有受到官方的認證，但是有明明快死的人，用了聖水後就活過來的證詞出現。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게...... 가능해?","JPN":"それって……あり得るの？","ENG":"Is that... even possible?","TWN":"這……這怎麼可能？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 상식적으로 생각하세요.","JPN":"ミナさん、常識的に考えてください。","ENG":"Think about it rationally, Mina.","TWN":"米娜小姐，妳用常識想想。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"죽은 사람이 살아날 수는 없습니다.","JPN":"死んだ人が生き返ることはできません。","ENG":"There’s no way for a dead person to come back to life.","TWN":"死人是無法復活的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"만약 살아났다면 애초에 죽지 않았거나......","JPN":"もし生き返ったなら、そもそも死んでないか……","ENG":"If they did, they must’ve not died in the first place...","TWN":"不是還活著，就是從一開始就沒死……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"죽은 자와 살아난 자는 서로 다른 존재일 겁니다.","JPN":"死んだ者と生き返った者は別人なんでしょう。","ENG":"Or whoever came back to life is an entirely different person than before.","TWN":"死去的人和現在活過來的人已經不是同一個人了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건...... 그렇지만......","JPN":"それは……そうだけど……","ENG":"I know... but still...","TWN":"這……可是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"상식적으로는 물론 그렇습니다만......","JPN":"常識的にはもちろんそうですが……","ENG":"Yes, rationally it doesn’t seem to make any sense.","TWN":"以常識來說當然是這樣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"목숨을 걸고 일하는 용병들에게는 아주 매력적인 이야기였겠죠.","JPN":"命をかけて働く傭兵たちにとっては、非常に魅力的な話でしょうね。","ENG":"But I’m sure the prospect sounded very appealing to mercenaries who put their lives on the line.","TWN":"但對於冒著生命危險工作的傭兵來說，是非常誘人的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"설사 부활이 거짓말이라고 해도 신체능력 상승과 강력한 재생 능력은 진짜니까요.","JPN":"たとえ復活は嘘だとしても、身体能力の上昇と強力な再生能力は本物ですから。","ENG":"Even if the tales of resurrection turned out to be false, the enhancement of physical abilities and boosted regeneration are true, after all.","TWN":"而且就算復活是謠言，但提升身體能力和強大的再生能力卻是貨真價實的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말하자면 여벌 목숨이라는 느낌이네요.","JPN":"いうなれば、スペアの命といった感じですね。","ENG":"So in essence, you get a spare life.","TWN":"也就是多了一條命的感覺。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그렇게 좋기만 할 리는 없을 것 같은데요.","JPN":"しかし、そんなに良いことばかりではなさそうですけどね。","ENG":"But I get a feeling that that’s not the full story.","TWN":"但應該不會只有好處才對啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부작용 같은 건 없었나요?","JPN":"副作用などはありませんでしたか。","ENG":"Aren’t there any side effects?","TWN":"難道沒有副作用嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......없을 리가 있겠어?","JPN":"……ないわけがない。","ENG":"Of course there are.","TWN":"……怎麼可能會沒有？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"반복 투약을 할 경우 이성을 잃고 미치광이가 되거나, 재생력이 폭주해서 암 덩어리 같은 괴물로 바뀌어 버릴 수도 있다고.","JPN":"投薬を繰り返した場合、理性を失って狂人になるか、\\n再生力が暴走して癌の塊のような怪物になる恐れもあります。","ENG":"Repeated use can lead to mania, or over-stimulation of the regenerative capabilities, which turns you into a monstrous lump of tumors.","TWN":"不斷使用的話，不是發瘋，就是再生能力暴走，變成一隻長滿腫瘤的怪物。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호오.......","JPN":"なるほど……","ENG":"Ooh...","TWN":"哦……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그리고 무엇보다 제일 짜증나는 건......","JPN":"そしてなによりも癪に障るのは……","ENG":"What annoys me the most are...","TWN":"而且最令人困擾的是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"자기가 슈퍼히어로라도 된 줄 아는 무능력자들이야!","JPN":"スーパーヒーローになったつもりの勘違い野郎どもだ！","ENG":"...non-powered incompetents who think they've suddenly become some sort of superheroes!","TWN":"那些以為自己能成為超級英雄的無能力者們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 또 무슨 소리야?","JPN":"それはまた、どういうこと？","ENG":"What’s that about?","TWN":"這又是什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 이 경우는 슈퍼 빌런이라고 해야겠죠.","JPN":"あはは、この場合はスーパーヴィランと言うべきでしょうね。","ENG":"Haha, I guess the correct term here would be “supervillains.”","TWN":"哈哈，這種情況應該叫超級反派才對。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"엘릭서가 대량으로 유통되고 나서 엘릭서를 이용한 일반인들의 범죄가 꽤 많이 발생했거든요.","JPN":"エリクサーが大量に流通してから、エリクサーを利用した一般人の犯罪が多発したんですよ。","ENG":"Since the mass distribution of Elixir, we saw a spike in crimes committed by ordinary people abusing the drug.","TWN":"聖水大量流通之後，發生了很多普通人非法使用聖水的犯罪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그리고 엘릭서 사용자의 범죄를 막는다는 이유로 또 다른 엘릭서를 복용한 일반인들 간에 싸움이 벌어지고......","JPN":"そして、その犯罪を防ぐという名目で、エリクサーを服用した一般人の間でいざこざが起こり……","ENG":"Under the pretense of stopping crimes committed by Elixir users, other people began taking Elixir to fight them...","TWN":"然後以為了防止聖水犯罪為理由，其他的普通人也開始使用聖水，展開無止盡的糾紛……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"난장판이 따로 없다니까요.","JPN":"もう修羅場状態です。","ENG":"The whole situation’s been a total mess, really.","TWN":"簡直是一團混亂呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"덕분에 최근 저와 유미 경정님의 업무 대부분이 엘릭서 관련 수사라고 해도 과언이 아니에요.","JPN":"おかげで最近は、私とカスカベ警視様の業務のほとんどが\\nエリクサー関連の捜査と言っても過言ではありません。","ENG":"Because of all that, I wouldn’t be exaggerating if I said most of our work has been investigating Elixir-related cases.","TWN":"拜這所賜，把我和悠美警正最近的業務全說成是聖水的相關調查，都不會太過分呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"힘에 대한 경각심도 없는 놈들이 멋대로 약에 취해서는......","JPN":"力に対して警戒心もないやつらが勝手にドラッグを乱用して……","ENG":"Those junkies don't even understand the dangers of wielding power...","TWN":"就是因為這些傢伙對力量毫無警惕，隨便亂吃藥……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"제멋대로 사람들을 괴롭히고 다니고 있다고!","JPN":"好き勝手に人々を虐げているのよ！","ENG":"All they've been doing is harassing the innocent!","TWN":"把我們折磨得要死！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런 거...... 그런 거, 용서할 수 있을 리가 없잖아?!","JPN":"そんなの……そんなの、許せるわけないじゃない！","ENG":"I couldn’t possibly... let such crimes go unpunished!","TWN":"這種事情……這種事情，怎麼可以原諒？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 자. 진정하세요, 경정님.","JPN":"まあまあ、落ち着いてください、警視様。","ENG":"There, there. Take it down a notch, Major.","TWN":"好了，好了。警正大人，冷靜一點。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 저희가 그런 일을 막고 있잖아요.","JPN":"だから、私たちがそれを阻止してるんでしょう。","ENG":"So yeah, that’s the sort of thing we've been trying to stop.","TWN":"所以我們不是正在阻止這些事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어떤가요? 원하시던 정보가 맞나요?","JPN":"いかがですか？　これがお求めの情報ですか。","ENG":"So what do you think? Is this the sort of intel you wanted?","TWN":"怎麼樣？是你們想要的情報嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......흥미롭군.","JPN":"……興味深いな。","ENG":"...Interesting.","TWN":"……很有意思。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"좀 더 자세한 이야기를 들어봤으면 좋겠는데.","JPN":"もっと詳しい話を聞いてみたいんだが。","ENG":"I'd like to hear more details about this.","TWN":"要是能再多聽一點詳細內容就更好了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 엘릭서란 걸 만든 놈들에 대해서 아는 게 있나?","JPN":"そのエリクサーとやらを作ったやつらについて、何か知っているのか？","ENG":"Do you have anything on who made the Elixir?","TWN":"你們知道有沒有什麼和製造聖水有關的傢伙嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"워낙 철저한 점조직으로 유통되고 있어서 제작자를 찾는 데 꽤나 고생을 했습니다만......","JPN":"流通に関わる組織が点在しているせいで、製造者の調査はかなり困難を極めましたが……","ENG":"It's been quite tricky trying to pinpoint the manufacturer since the entire distribution network is comprised of discrete dealers and middlemen...","TWN":"由於它在市面上太過流通，所以要找到生產者花了我們不少力氣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네, 최근에 겨우 꼬리를 잡았습니다.","JPN":"はい、最近ようやく尻尾をつかみました。","ENG":"But yeah, we eventually found a lead.","TWN":"但最近，我們終於揪出他們的尾巴了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"마젤란 예언회라는 사이비 종교단체에서 엘릭서를 제조하고 있다는 정보를 입수했습니다.","JPN":"マジェラン預言会というインチキ宗教団体で、エリクサーを製造しているという情報を入手しました。","ENG":"According to our intel, a religious cult known as Magellan's Prediction Society has been producing Elixir.","TWN":"我們得到了一個情報，說有個叫麥哲倫預言會的邪教團體正在生產聖水。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......마젤란 예언회?","JPN":"……マジェラン預言会?","ENG":"Magellan's Prediction Society?","TWN":"……麥哲倫預言會？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"익숙한 이름이군. 혹시 좀 전에 달려든 그놈들인가?","JPN":"聞いたことのある名前だな。もしかして、さっきのやつらか。","ENG":"Sounds familiar. You mean those bastards who were after you earlier?","TWN":"好耳熟的名字啊。是之前攻擊我們的傢伙嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"そうです。","ENG":"That's right.","TWN":"是的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"사이비 종교단체라고는 하지만 엘릭서로 강화된 신도들은 물론, 거의 준 군사조직에 가까운 무장을 갖추고 있는 자들입니다.","JPN":"エセ宗教団体とはいえ、エリクサーで強化された信徒はもちろん、\\n準軍事組織と言えるほど武装している集団です。","ENG":"They may sound like a fanatical cult, but they are basically a paramilitary organization with firearms as well as followers enhanced with Elixir.","TWN":"而雖說是邪教團體，但先不說那些用聖水強化過的信徒，他們這群人擁有接近於準軍事組織的武裝。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"거기다 최근에는 대체 무슨 방법을 썼는지, 침식체들을 길들여서 경비에 동원하고 있더라고요?","JPN":"それに最近はいったいどんな手を使ったのか、侵食体を手なずけて警備させているんです。","ENG":"And recently, they've somehow managed to tame Corrupted Objects to boost their security.","TWN":"而且，最近他們不知道用了什麼方法，還把侵蝕體馴化成組織的警衛了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이래서야 경찰 특공대 정도로는 도저히 손을 쓸 수가 없죠.","JPN":"これでは、警察程度ではどうしようもありません。","ENG":"At this rate, even a police SWAT team doesn’t have the firepower to take these guys down.","TWN":"這樣一來，警察特攻隊也處理不了他們了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"원래대로라면 다른 태스크포스들과 함께 일망타진할 계획이었습니다만......","JPN":"本来なら他のタスクフォースカンパニーと共同で一網打尽にするはずでしたが……","ENG":"Originally, the plan was to partner up with other TASKFORCEs and put them out of commission...","TWN":"本來，我們想要和其他特遣勢力聯手，將他們一網打盡的……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이번 사건이 터졌군요.","JPN":"今回の事件が起こったんですね。","ENG":"But then this happened.","TWN":"沒想到卻爆發了這次事件。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네...... 태스크포스들의 발이 다 묶여 버린 상황이라서요.","JPN":"はい……タスクフォースが足止めされている状況ですからね。","ENG":"I’m afraid so... All the TASKFORCEs are preoccupied elsewhere now.","TWN":"是的……特遣勢力現在都忙得不可開交。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"거기다 얼마 전에 저희가 마젤란 예언회의 간부 하나를 체포한 뒤로 위기감을 느꼈는지, 이젠 아주 대놓고 먼저 습격을 해 오더라고요.","JPN":"しかも、先日私たちに幹部の一人を逮捕され危機感を持ったのか、最近は堂々と襲撃をかけてくるんです。","ENG":"Worse yet, we must've made them uneasy when we arrested one of their officers. Those bastards were brazen enough to attack us outright.","TWN":"而且，不久前我們逮捕了一個麥哲倫預言會的幹部，大概是產生了危機感吧，他們現在已經無所顧慮，主動襲擊過來了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"조금 전처럼 말이죠.","JPN":"さっきのように。","ENG":"Like just now.","TWN":"就像剛才那樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그래서 기회다 싶어 여기로 끌고 오신 거로군요.","JPN":"ハハハ、それでチャンスだと思って、ここに連れてこられたんですね。","ENG":"Haha, so you decided to take advantage of this situation and lure them here.","TWN":"哈哈，所以你們看準時機，把我們叫到這裡來啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"우리가 어쩔 수 없이 휘말리도록.","JPN":"僕たちがやむを得ず巻き込まれることを期待して。","ENG":"You wanted us to get involved without a choice.","TWN":"為了讓我們無可奈何地被牽扯進來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 설마 그럴 리가 있겠어요?","JPN":"ははは、まさかそんなことあるわけないじゃないですか。","ENG":"Haha, of course not...","TWN":"哈哈，怎麼可能呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우연이죠, 우연.","JPN":"たまたまです、たまたま。","ENG":"It’s merely a coincidence.","TWN":"是巧合而已啦，巧合。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 어차피 마젤란 예언회에 볼일이 있으시다고 하니......","JPN":"でも、どのみちマジェラン預言会に用があるとのことだったので……","ENG":"But since you've got business with the Magellan's Prediction Society...","TWN":"反正你們不是也找麥哲倫預言會有事嘛……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이 기회에 일망타진해 주시면 누이 좋고 매부 좋고 아닐까요?","JPN":"この機に一網打尽に\\nしていただければ、お互いハッピーじゃないですかね？","ENG":"It could benefit us both if you could round them up.","TWN":"我們就藉這個機會把他們一網打盡，這不是皆大歡喜嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 참 뻔뻔하시네요.","JPN":"ハハ、本当に厚かましいですね。","ENG":"Haha, wow that's quite shameless of you.","TWN":"哈哈，臉皮真厚呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 별말씀을.","JPN":"はは、とんでもないです。","ENG":"Haha, oh you're far too kind.","TWN":"哈哈，不敢當。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하하.","JPN":"アハハ。","ENG":"Hahaha...","TWN":"哈哈哈。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하하하.","JPN":"ハハハハ。","ENG":"Hahahaha...","TWN":"哈哈哈哈。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"가끔 느끼는 건데......","JPN":"時々思うけど……","ENG":"You know what...","TWN":"我偶爾覺得……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저렇게 순수하게 웃는 얼굴로 사람을 불쾌하게 만드는 것도 일종의 재능이 아닐까 싶어.","JPN":"あんなあどけない笑顔で人を不愉快にさせるのも、ある種の才能なんじゃないかな。","ENG":"Sometimes I begin to think it takes real talent to offend people with such an innocent smile.","TWN":"能用那種天真的笑容讓別人感到不舒服，也是一種才能呢……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......동감이다.","JPN":"……同感だ。","ENG":"Agreed.","TWN":"……我有同感。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼 마젤란 예언회의 본부로 안내하겠습니다.","JPN":"それでは、マジェラン預言会の本部にご案内いたします。","ENG":"Alright then, we’ll lead you to the Magellan's Prediction Society’s headquarters.","TWN":"那我就帶大家去麥哲倫預言會的總部吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};